package MayCodingquestions;

public class Evenandoddcode {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		int num=10;
		
		for(int i=0;i<=num;i++)
		{
			if(i%2==0)
			{
				System.out.println("number is Even "+i);
			}
			else
			{
				System.out.println("number is odd "+i);
			}
		}
	}

}
